import{_ as i,o as a,c as e,ag as s}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Compiling","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/ardusub/compiling/README.md","filePath":"robotics/ardusub/compiling/README.md"}'),o={name:"robotics/ardusub/compiling/README.md"};function n(r,t,l,h,d,p){return a(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="compiling" tabindex="-1">Compiling <a class="header-anchor" href="#compiling" aria-label="Permalink to &quot;Compiling&quot;">​</a></h1><h2 id="developers" tabindex="-1">Developers <a href="#developers" id="developers"></a> <a class="header-anchor" href="#developers" aria-label="Permalink to &quot;Developers &lt;a href=&quot;#developers&quot; id=&quot;developers&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><h3 id="how-to-get-the-code" tabindex="-1">How to Get the Code <a href="#how-to-get-the-code" id="how-to-get-the-code"></a> <a class="header-anchor" href="#how-to-get-the-code" aria-label="Permalink to &quot;How to Get the Code &lt;a href=&quot;#how-to-get-the-code&quot; id=&quot;how-to-get-the-code&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>ArduSub is hosted and maintained on <a href="https://github.com/ardupilot/ardupilot.git" target="_blank" rel="noreferrer">github</a>. You need to clone the repository to have full code access including submodules.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/ardupilot/ardupilot.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ardupilot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> submodule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recursive</span></span></code></pre></div><h3 id="build-ardusub" tabindex="-1">Build ArduSub <a href="#build-ardusub" id="build-ardusub"></a> <a class="header-anchor" href="#build-ardusub" aria-label="Permalink to &quot;Build ArduSub &lt;a href=&quot;#build-ardusub&quot; id=&quot;build-ardusub&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Before compiling ArduSub, first checkout the ArduSub-stable tag into a new branch (here we call it new-branch):</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> fetch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">tags</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ArduSub</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stable</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">b</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> new</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">branch</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> submodule</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> update</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">init</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">recursive</span></span></code></pre></div><p>To set up your build environment, follow these instructions:</p><ul><li><a href="http://ardupilot.org/dev/docs/building-setup-mac.html" target="_blank" rel="noreferrer">Mac Instructions</a></li><li><a href="http://ardupilot.org/dev/docs/building-setup-linux.html" target="_blank" rel="noreferrer">Linux Instructions</a></li><li><a href="http://ardupilot.org/dev/docs/building-setup-windows.html" target="_blank" rel="noreferrer">Windows Instructions</a></li></ul><blockquote><p>Skip the clone instructions in the links above, as they could cause you to use <strong>master</strong> instead of <strong>ArduSub-stable</strong> and lead the install scripts to install a different set of tools.</p></blockquote><h4 id="waf" tabindex="-1">WAF <a href="#waf" id="waf"></a> <a class="header-anchor" href="#waf" aria-label="Permalink to &quot;WAF &lt;a href=&quot;#waf&quot; id=&quot;waf&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Waf is a global build system for ArduPilot repository, it&#39;s necessary to be inside the root folder of ArduPilot to use it. You can check how to use waf with:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./waf --help</span></span></code></pre></div><p>To configure waf to build ArduSub for Pixhawk 1:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">waf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> configure</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">board</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Pixhawk1</span></span></code></pre></div><p>And to compile:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">waf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sub</span></span></code></pre></div><p>The firmware file will be created at <code>ardupilot/build/Pixhawk1/bin/ardusub.apj</code></p><p><strong>Uploading Locally</strong></p><p>This only works with a direct USB connection to the Pixhawk, and to upload the code:</p><p><strong>waf</strong>: Use <code>--upload</code> with the vehicle type (only works after configuring and building with <code>waf</code> before).</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./waf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --upload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sub</span></span></code></pre></div><h4 id="uploading-remotely" tabindex="-1">Uploading Remotely <a href="#uploading-remotely" id="uploading-remotely"></a> <a class="header-anchor" href="#uploading-remotely" aria-label="Permalink to &quot;Uploading Remotely &lt;a href=&quot;#uploading-remotely&quot; id=&quot;uploading-remotely&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>With an Ethernet tether and companion computer, it is possible to flash the Pixhawk firmware through the companion computer - no need to directly access the Pixhawk.</p><p><strong>Flashing Via Web Interface</strong></p><p>Navigate to <a href="http://192.168.2.2:2770/system" target="_blank" rel="noreferrer">192.168.2.2:2770/system</a> in your browser. Under the &#39;Pixhawk Firmware Update&#39; section, click &#39;Browse&#39; and select the firmware file (.apj) saved on your computer. Click &#39;Upload&#39; and wait for the flashing process to complete.</p><h3 id="running" tabindex="-1">Running <a href="#running" id="running"></a> <a class="header-anchor" href="#running" aria-label="Permalink to &quot;Running &lt;a href=&quot;#running&quot; id=&quot;running&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>The code begins running immediately once uploaded. For Linux-based autopilots, it must be launched or started with launch script. Please see the documentation for your respective autopilot.</p><h3 id="making-a-custom-configuration" tabindex="-1">Making a Custom Configuration <a href="#making-a-custom-configuration" id="making-a-custom-configuration"></a> <a class="header-anchor" href="#making-a-custom-configuration" aria-label="Permalink to &quot;Making a Custom Configuration &lt;a href=&quot;#making-a-custom-configuration&quot; id=&quot;making-a-custom-configuration&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>One of the biggest additions to the ArduSub code is a six degree-of-freedom motor library that allows a wide variety of motor configurations to be set up easily. The motors libraries for each configuration are built on a set of higher-level motor classes as follows:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">AP_Motors</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    |----</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> AP_MotorsMulticopter</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">                   |----</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> AP_MotorsMatrix</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">                                |----</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> AP_Motors6DOF</span></span></code></pre></div><p>To add a new motor configuration, you will need to add your custom motor setup to <a href="https://github.com/ardupilot/ardupilot/blob/master/libraries/AP_Motors/AP_Motors6DOF.cpp" target="_blank" rel="noreferrer">AP_Motors6DOF.cpp</a>. Find the following line, and add your frame configuration there. The frame is configured at boot according to the FRAME_CONFIG parameter. You will need to change this parameter to CUSTOM to use your custom frame.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">case</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> AS_MOTORS_CUSTOM_FRAME</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Put your custom motor setup here</span></span></code></pre></div><p>The behavior of each motor will be defined by its assigned contributions to each of the 6 degrees of freedom in AP_Motors6DOF.cpp. You can use the other frame configurations as a reference guide to defining your own custom configuration. Here is the BlueROV1 frame configuration as an example:</p><table tabindex="0"><thead><tr><th>Motor #</th><th>Roll Factor</th><th>Pitch Factor</th><th>Yaw Factor</th><th>Throttle Factor</th><th>Forward Factor</th><th>Lateral Factor</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>0</td><td>-1.0</td><td>0</td><td>1.0</td><td>0</td></tr><tr><td>2</td><td>0</td><td>0</td><td>1.0</td><td>0</td><td>1.0</td><td>0</td></tr><tr><td>3</td><td>-0.5</td><td>0.5</td><td>0</td><td>0.45</td><td>0</td><td>0</td></tr><tr><td>4</td><td>0.5</td><td>0.5</td><td>0</td><td>0.45</td><td>0</td><td>0</td></tr><tr><td>5</td><td>0</td><td>-1.0</td><td>0</td><td>1.0</td><td>0</td><td>0</td></tr><tr><td>6</td><td>-0.25</td><td>0</td><td>0</td><td>0</td><td>0</td><td>1.0</td></tr></tbody></table><p><img src="https://www.ardusub.com/images/bluerov-frame.png" alt=""></p><h3 id="using-the-new-custom-configuration" tabindex="-1">Using the New Custom Configuration <a href="#using-the-new-custom-configuration" id="using-the-new-custom-configuration"></a> <a class="header-anchor" href="#using-the-new-custom-configuration" aria-label="Permalink to &quot;Using the New Custom Configuration &lt;a href=&quot;#using-the-new-custom-configuration&quot; id=&quot;using-the-new-custom-configuration&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>To use the newly created frame, set the <strong>FRAME_CONFIG</strong> parameter to &quot;Custom&quot; in QGroundControl and then reboot the flight controller.</p><p><img src="https://www.ardusub.com/images/custom_frame.png" alt=""></p><h3 id="troubleshooting" tabindex="-1">Troubleshooting <a href="#troubleshooting" id="troubleshooting"></a> <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting &lt;a href=&quot;#troubleshooting&quot; id=&quot;troubleshooting&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ol><li>If something goes wrong while compiling: <ol><li>Check the <a href="https://www.ardusub.com/developers/developers.html#compiling" target="_blank" rel="noreferrer">compiling</a> section to set up your environment.</li><li>ArduSub is only compatible with GCC 6. Be sure that &quot;gcc-arm-none-eabi 6&quot; is your &quot;PATH&quot; env with: <code>echo $PATH | grep gcc-arm-none-eabi</code>. <ol><li>It&#39;s also possible to add custom paths for the compiler with <code>export PATH=/your_path/gcc-arm-none-eabi-6-2017-q2-update/bin/:$PATH</code>. Run <code>./waf configure --board Pixhawk1</code> again if compiling with <a href="https://www.ardusub.com/developers/developers.html#waf" target="_blank" rel="noreferrer">WAF</a>.</li></ol></li></ol></li></ol><p>Sponsored by <a href="http://www.bluerobotics.com/" target="_blank" rel="noreferrer">Blue Robotics</a>. Code released under the <a href="https://github.com/ardupilot/ardupilot/blob/master/COPYING.txt" target="_blank" rel="noreferrer">GPLv3 License</a>. Documentation released under the <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-NC-SA 4.0</a>.<br><a href="https://github.com/bluerobotics/ardusub-gitbook/issues/" target="_blank" rel="noreferrer">Submit a Documentation GitHub Issue here</a> to report any errors, suggestions, or missing information in this documentation.<br><a href="https://github.com/ArduPilot/ardupilot/issues/new/choose" target="_blank" rel="noreferrer">Submit an ArduSub GitHub Issue here</a> to report issues with the ArduSub software.</p>`,43)])])}const g=i(o,[["render",n]]);export{c as __pageData,g as default};
